<script setup lang="ts">
import type { RandomEvent } from "~/types/random-event";
import EventImportPanel from "~/components/events/EventImportPanel.vue";
definePageMeta({ middleware: ["auth", "admin-client"] }); useSeoMeta({ title: "事件管理 · 躲避堡垒 3" });
type Link = { family: "map" | "achievement"; challengeId: string }; type AdminChallenge = { challengeId: string; family: "map" | "achievement"; name?: string; titleName?: string };
const api = useAdminApi(); const events = ref<RandomEvent[]>([]); const challenges = ref<AdminChallenge[]>([]); const loading = shallowRef(true); const saving = shallowRef(false); const error = shallowRef(""); const query = shallowRef(""); const showArchived = shallowRef(false); const editing = shallowRef<RandomEvent | null>(null); const form = reactive({ name: "", category: "", rarity: "", description: "", durationSeconds: "", cooldownSeconds: "", weight: "", appearanceProbability: "", gameVersion: "", effectTags: "", releaseStatus: "development" as RandomEvent["releaseStatus"], links: [] as Link[] });
const visible = computed(() => events.value.filter((event) => event.name.includes(query.value) || event.category.includes(query.value)));
function reset(event?: RandomEvent) { editing.value = event ?? null; Object.assign(form, event ? { name:event.name, category:event.category, rarity:event.rarity, description:event.description, durationSeconds:event.durationSeconds ?? "", cooldownSeconds:event.cooldownSeconds ?? "", weight:event.weight ?? "", appearanceProbability:event.appearanceProbability ?? "", gameVersion:event.gameVersion, effectTags:event.effectTags.join("、"), releaseStatus:event.releaseStatus, links:event.challenges.map((challenge) => ({ family:challenge.family, challengeId:challenge.challengeId })) } : { name:"", category:"", rarity:"", description:"", durationSeconds:"", cooldownSeconds:"", weight:"", appearanceProbability:"", gameVersion:"", effectTags:"", releaseStatus:"development", links:[] }); }
async function load() { loading.value = true; try { const [eventResponse, challengeResponse] = await Promise.all([api<{ items: RandomEvent[] }>(`/v1/events?archived=${showArchived.value}`), api<{ items: AdminChallenge[] }>("/v1/achievements")]); events.value = eventResponse.items; challenges.value = challengeResponse.items.filter((item) => item.family === "map" || item.family === "achievement"); } catch (cause:any) { error.value = cause?.data?.error?.message ?? "无法读取事件目录。"; } finally { loading.value = false; } }
function toggle(link: Link) { form.links = form.links.some((item) => item.family === link.family && item.challengeId === link.challengeId) ? form.links.filter((item) => item.family !== link.family || item.challengeId !== link.challengeId) : [...form.links, link]; }
async function save() { saving.value = true; error.value = ""; const number = (value:string) => value === "" ? null : Number(value); const body = { contractVersion:"1" as const, name:form.name, category:form.category, rarity:form.rarity, description:form.description, durationSeconds:number(form.durationSeconds), cooldownSeconds:number(form.cooldownSeconds), weight:number(form.weight), appearanceProbability:number(form.appearanceProbability), gameVersion:form.gameVersion, effectTags:form.effectTags.split(/[、,]/).map((value) => value.trim()).filter(Boolean), releaseStatus:form.releaseStatus, challengeLinks:form.links }; try { if (editing.value) await api(`/v1/events/${encodeURIComponent(editing.value.eventId)}`, { method:"PUT", headers:{ "Idempotency-Key":crypto.randomUUID() }, body }); else await api("/v1/events", { method:"POST", headers:{ "Idempotency-Key":crypto.randomUUID() }, body }); reset(); await load(); } catch (cause:any) { error.value = cause?.data?.error?.message ?? "无法保存事件。"; } finally { saving.value = false; } }
async function archive(event:RandomEvent) { if (!window.confirm(`归档“${event.name}”？`)) return; await api(`/v1/events/${encodeURIComponent(event.eventId)}`, { method:"DELETE", headers:{ "Idempotency-Key":crypto.randomUUID() } }); await load(); }
onMounted(() => void load()); watch(showArchived, () => void load());
</script>
<template><AdminWorkspace title="事件管理" :count="loading ? '读取中…' : `${events.length} 条`"><template #messages><UAlert v-if="error" color="error" variant="subtle" :description="error" /></template><EventImportPanel @imported="load" /><section class="toolbar"><UInput v-model="query" placeholder="搜索事件" /><UCheckbox v-model="showArchived" label="包含已归档" /><UButton label="新建事件" @click="reset()" /></section><section class="layout"><div class="event-list"><p v-if="loading">读取中…</p><button v-for="event in visible" :key="event.eventId" class="event-row" type="button" @click="reset(event)"><span><strong>{{ event.name }}</strong><small>{{ event.category }} · {{ event.rarity }} · {{ event.gameVersion }}</small></span><StatusBadge :label="event.releaseStatus === 'implemented' ? '已实装' : event.releaseStatus === 'removed' ? '已移除' : '开发中'" :tone="event.releaseStatus === 'implemented' ? 'success' : 'warning'" /></button><UEmpty v-if="!loading && !visible.length" title="暂无事件" description="可新建事件或导入 CSV。" variant="naked" /></div><form class="editor" @submit.prevent="save"><div class="editor-head"><h2>{{ editing ? '编辑事件' : '新建事件' }}</h2><UButton v-if="editing" label="归档" color="error" variant="link" type="button" @click="archive(editing)" /></div><div class="form-grid"><UFormField label="名称"><UInput v-model="form.name" required /></UFormField><UFormField label="类别"><UInput v-model="form.category" required /></UFormField><UFormField label="稀有度"><UInput v-model="form.rarity" required /></UFormField><UFormField label="版本"><UInput v-model="form.gameVersion" required /></UFormField><UFormField label="持续时间（秒）"><UInput v-model="form.durationSeconds" type="number" min="0" /></UFormField><UFormField label="内置冷却（秒）"><UInput v-model="form.cooldownSeconds" type="number" min="0" /></UFormField><UFormField label="权重"><UInput v-model="form.weight" type="number" min="0" step="any" /></UFormField><UFormField label="最终出现概率"><UInput v-model="form.appearanceProbability" type="number" min="0" max="1" step="any" /></UFormField></div><UFormField label="内容说明"><UTextarea v-model="form.description" required :rows="4" /></UFormField><UFormField label="效果标签"><UInput v-model="form.effectTags" placeholder="用顿号或逗号分隔" /></UFormField><UFormField label="事件状态"><USelect v-model="form.releaseStatus" :items="[{label:'开发中',value:'development'},{label:'已实装',value:'implemented'},{label:'已移除',value:'removed'}]" /></UFormField><fieldset class="links"><legend>关联挑战</legend><label v-for="challenge in challenges" :key="`${challenge.family}-${challenge.challengeId}`"><UCheckbox :model-value="form.links.some((link) => link.family === challenge.family && link.challengeId === challenge.challengeId)" @update:model-value="toggle({ family:challenge.family, challengeId:challenge.challengeId })" />{{ challenge.name ?? challenge.titleName }}</label></fieldset><div class="save-actions"><UButton type="submit" :label="editing ? '保存事件' : '创建事件'" :loading="saving" /></div></form></section></AdminWorkspace></template>
<style scoped>.toolbar { display:flex; flex-wrap:wrap; align-items:center; gap:10px; margin:20px 0; }.toolbar > :first-child { min-width:min(100%,260px); flex:1; }.layout { display:grid; grid-template-columns:minmax(230px,.75fr) minmax(0,1.25fr); overflow:hidden; border:1px solid var(--line); border-radius:14px; }.event-list { display:grid; align-content:start; border-right:1px solid var(--line); }.event-row { display:flex; align-items:center; justify-content:space-between; gap:10px; padding:14px; border:0; border-bottom:1px solid var(--line); color:var(--text); background:transparent; cursor:pointer; text-align:left; }.event-row:hover { background:var(--surface); }.event-row strong,.event-row small { display:block; }.event-row small { margin-top:4px; color:var(--quiet); font-size:.75rem; }.editor { display:grid; gap:15px; padding:20px; }.editor-head { display:flex; align-items:center; justify-content:space-between; }.editor-head h2 { margin:0; font-size:1.35rem; letter-spacing:-.04em; }.form-grid { display:grid; grid-template-columns:repeat(2,minmax(0,1fr)); gap:12px; }.links { display:grid; gap:8px; padding:12px; border:1px solid var(--line); border-radius:10px; }.links legend { padding:0 5px; color:var(--muted); font-size:.8rem; }.links label { display:flex; align-items:center; gap:8px; font-size:.82rem; }.save-actions { display:flex; justify-content:flex-end; } @media (max-width:760px) { .layout { grid-template-columns:1fr; }.event-list { border-right:0; border-bottom:1px solid var(--line); max-height:260px; overflow:auto; }.form-grid { grid-template-columns:1fr; } }</style>
